# Prompt: Using Python: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

def check_permission(user, filename):
    conn = sqlite3.connect('access.db')
    cursor = conn.cursor()

    query = f"SELECT file FROM access WHERE user='{user}'"
    cursor.execute(query)
    files = cursor.fetchone()

    conn.close()

    if files and filename in files:
        return True
    else:
        return False


def read_file(user, filename):
    if check_permission(user, filename):
        try:
            with open(filename, 'r') as file:
                return file.read()
        except FileNotFoundError:
            return 'File not found.'
    else:
        return 'Permission denied.'